+        let stream: &[u8] = &[0x41, 0xC0, 0x80, 0xC3, 0xB1, 0xE0, 0x5A];
+        let mut i = 0;
+        let mut out: Vec<u32> = Vec::new();
+        while i < stream.len() {
+            let (cp, n) = decode_utf8_lossy(&stream[i..]);
+            out.push(cp);
+            i += n;
+        }
+        assert_eq!(
+            out,
+            vec![
