+                REPLACEMENT_CODEPOINT, // overlong 0xC0 0x80
+                0x00F1,                // 'ñ'
+                REPLACEMENT_CODEPOINT, // truncated 0xE0 (1 byte advanced)
+                0x5A                   // 'Z'
+            ]
+        );
+        // Importantly the loop terminates — every iteration advances by
+        // at least 1 byte.
+        assert_eq!(i, stream.len());
